def run_code(code, progress_callback=None):
    class StreamToCallback(io.StringIO):
        def write(self, s):
            if progress_callback and '[PROGRESS:' in s:
                progress_callback.onProgress(s.strip())
            return super().write(s)

    output = StreamToCallback()
    sys.stdout = output
    sys.stderr = output

    try:
        exec(code, agent_globals)
        result = output.getvalue()
    except Exception:
        result = traceback.format_exc()
    finally:
        sys.stdout = sys.__stdout__
        sys.stderr = sys.__stderr__

    return result or "Code executed successfully."

